// K-Map Simplification for 2 variables
#include <stdio.h>

int main() {
    // F = Σ(0,1,3) - SOP form
    int kmap[2][2] = {{1, 1},  // m0, m1
                      {0, 1}}; // m2, m3

    // Check groups of 2 (horizontal and vertical)
    // Group 1: m0,m1 (row 0) - eliminates B
    // Group 2: m0,m2 (column 0) - eliminates A
    // Group 3: m1,m3 (column 1) - eliminates A, adds B'

    // Simplified: F = A' + B'

    printf("K-Map for F(A,B) = Σ(0,1,3)\n");
    printf("Simplified: F = A' + B'\n");

    return 0;
}
